        # Parse the expression into an AST
        tree = ast.parse(transform_map_expr, mode='eval')

        # Transform the AST to replace 'input_data' with actual data and validate
        transformer = SafeTransformer(input_data)
        safe_tree = transformer.visit(tree.body)

        # Evaluate the transformed AST safely
        evaluator = SafeEvaluator(safe_operators)
        result = evaluator.visit(safe_tree)

        # Ensure the result is a dictionary
        if not isinstance(result, dict):
            raise ValueError("Expression must evaluate to a dictionary")

        return result

    except SyntaxError as e:
        raise SyntaxError(f"Invalid expression syntax: {e}")
    except (ValueError, TypeError, KeyError, IndexError) as e:
        raise ValueError(f"Error evaluating expression: {e}")

"""
Workflow data transformation module for processing step outputs.
"""

import ast
import operator


def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Transforms input data using a provided expression string.

    Args:
        transform_map_expr: A string representing a Python dictionary literal
                           that defines how to map input fields to output fields.
        input_data: Dictionary containing the input data from a previous step.

    Returns:
        A new dictionary with transformed data according to the expression.

    Raises:
        ValueError: If the expression contains unsafe operations or syntax errors.
        TypeError: If the expression doesn't evaluate to a dictionary.
    """
    # Validate that the expression is a dictionary literal or simple expression
    try:
        parsed_expr = ast.parse(transform_map_expr, mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid expression syntax: {e}")

    # Check for unsafe nodes in the AST
    safe_nodes = {
        ast.Expression, ast.Dict, ast.Constant, ast.List, ast.Tuple, ast.Set,
        ast.Name, ast.Subscript, ast.Attribute, ast.BinOp, ast.UnaryOp,
        ast.Compare, ast.BoolOp, ast.Call, ast.keyword
    }

    unsafe_nodes = {
        ast.Lambda, ast.ListComp, ast.SetComp, ast.DictComp, ast.GeneratorExp,
        ast.Yield, ast.YieldFrom, ast.Await, ast.AsyncFor, ast.AsyncWith,
        ast.AsyncFunctionDef, ast.NamedExpr, ast.Starred
    }

    for node in ast.walk(parsed_expr):
        node_type = type(node)
        if node_type in unsafe_nodes:
            raise ValueError(f"Unsafe expression component: {node_type.__name__}")
        if node_type not in safe_nodes:
            # Check for specific allowed operations
            if isinstance(node, ast.Call):
                # Only allow calls to safe built-in functions
                if not isinstance(node.func, ast.Name):
                    raise ValueError(f"Unsafe function call: {ast.dump(node.func)}")
                allowed_funcs = {'str', 'int', 'float', 'bool', 'len', 'list', 
                                'tuple', 'dict', 'set', 'sum', 'min', 'max', 'abs'}
                if node.func.id not in allowed_funcs:
                    raise ValueError(f"Unsafe function: {node.func.id}")

    # Create a safe evaluation context
    safe_builtins = {
        'str': str,
        'int': int,
        'float': float,
        'bool': bool,
        'len': len,
        'list': list,
        'tuple': tuple,
        'dict': dict,
        'set': set,
        'sum': sum,
        'min': min,
        'max': max,
        'abs': abs,
        'None': None,
        'True': True,
        'False': False
    }

    # Safe operators for arithmetic and comparisons
    safe_operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.Is: operator.is_,
        ast.IsNot: operator.is_not,
        ast.In: lambda a, b: a in b,
        ast.NotIn: lambda a, b: a not in b,
        ast.And: lambda *args: all(args),
        ast.Or: lambda *args: any(args),
        ast.Not: operator.not_
    }

    class SafeEvaluator(ast.NodeVisitor):
        def __init__(self, locals_dict):
            self.locals = locals_dict

        def evaluate(self, node):
            if isinstance(node, ast.Expression):
                return self.evaluate(node.body)
            elif isinstance(node, ast.Constant):
                return node.value
            elif isinstance(node, ast.Dict):
                keys = [self.evaluate(k) for k in node.keys]
                values = [self.evaluate(v) for v in node.values]
                return dict(zip(keys, values))
            elif isinstance(node, ast.List):
                return [self.evaluate(e) for e in node.elts]
            elif isinstance(node, ast.Tuple):
                return tuple(self.evaluate(e) for e in node.elts)
            elif isinstance(node, ast.Set):
                return {self.evaluate(e) for e in node.elts}
            elif isinstance(node, ast.Name):
                if node.id == 'input_data':
                    return self.locals['input_data']
                elif node.id in safe_builtins:
                    return safe_builtins[node.id]
                else:
                    raise ValueError(f"Undefined variable: {node.id}")
            elif isinstance(node, ast.Subscript):
                value = self.evaluate(node.value)
                slice_val = self.evaluate(node.slice)
                return value[slice_val]
            elif isinstance(node, ast.Attribute):
                obj = self.evaluate(node.value)
                return getattr(obj, node.attr)
            elif isinstance(node, ast.BinOp):
                left = self.evaluate(node.left)
                right = self.evaluate(node.right)
                op_type = type(node.op)
                if op_type not in safe_operators:
                    raise ValueError(f"Unsafe operator: {op_type.__name__}")
                return safe_operators[op_type](left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = self.evaluate(node.operand)
                op_type = type(node.op)
                if op_type not in safe_operators:
                    raise ValueError(f"Unsafe operator: {op_type.__name__}")
                return safe_operators[op_type](operand)
            elif isinstance(node, ast.Compare):
                left = self.evaluate(node.left)
                result = True
                for op, comparator in zip(node.ops, node.comparators):
                    right = self.evaluate(comparator)
                    op_type = type(op)
                    if op_type not in safe_operators:
                        raise ValueError(f"Unsafe operator: {op_type.__name__}")
                    if not safe_operators[op_type](left, right):
                        result = False
                        break
                    left = right
                return result
            elif isinstance(node, ast.BoolOp):
                values = [self.evaluate(v) for v in node.values]
                op_type = type(node.op)
                if op_type not in safe_operators:
                    raise ValueError(f"Unsafe operator: {op_type.__name__}")
                return safe_operators[op_type](*values)
            elif isinstance(node, ast.Call):
                func = self.evaluate(node.func)
                args = [self.evaluate(arg) for arg in node.args]
                kwargs = {kw.arg: self.evaluate(kw.value) for kw in node.keywords}
                return func(*args, **kwargs)
            elif isinstance(node, ast.keyword):
                return self.evaluate(node.value)
            else:
                raise ValueError(f"Unsupported node type: {type(node).__name__}")

    # Create the evaluation context
    context = {'input_data': input_data}

    # Evaluate the expression safely
    evaluator = SafeEvaluator(context)
    result = evaluator.evaluate(parsed_expr)

    # Ensure the result is a dictionary
    if not isinstance(result, dict):
        raise TypeError(f"Expression must evaluate to a dictionary, got {type(result).__name__}")

    return result
